(** val check_bounds : 'a1 expr -> 'a1 expr -> 'a1 expr **)

let check_bounds addr active_partition_size =
  BinBitBool (wordSz, wordSz, (Lt wordSz), (UniBit (memAddrSz, wordSz,
    (ZeroExtendTrunc (memAddrSz, wordSz)), addr)), active_partition_size)

(** val mem_read_tree_aux : int -> int -> 'a1 expr -> 'a1 expr -> 'a1 expr **)

let rec mem_read_tree_aux depth base addr memv =
  (fun fO fS n -> if n=0 then fO () else fS (n-1))
    (fun _ -> ReadIndex (memAddrSz, (Bit wordSz), (Const ((Bit memAddrSz),
    (ConstBit (memAddrSz, (natToWord memAddrSz base))))), memv))
    (fun d' ->
    let half = pow (Stdlib.Int.succ (Stdlib.Int.succ 0)) d' in
    let pivot = add base half in
    ITE ((SyntaxKind (Bit wordSz)), (BinBitBool (memAddrSz, memAddrSz, (Lt
    memAddrSz), addr, (Const ((Bit memAddrSz), (ConstBit (memAddrSz,
    (natToWord memAddrSz pivot))))))), (mem_read_tree_aux d' base addr memv),
    (mem_read_tree_aux d' pivot addr memv)))
    depth

(** val read_mem : 'a1 expr -> 'a1 expr -> 'a1 expr **)

let read_mem addr memv =
  mem_read_tree_aux memAddrSz 0 addr memv

(** val mem_write_tree_aux :
    int -> int -> 'a1 expr -> 'a1 expr -> 'a1 expr -> 'a1 expr **)

let rec mem_write_tree_aux depth base addr val0 memv =
  (fun fO fS n -> if n=0 then fO () else fS (n-1))
    (fun _ -> UpdateVector (memAddrSz, (Bit wordSz), memv, (Const ((Bit
    memAddrSz), (ConstBit (memAddrSz, (natToWord memAddrSz base))))),
    val0))
    (fun d' ->
    let half = pow (Stdlib.Int.succ (Stdlib.Int.succ 0)) d' in
    let pivot = add base half in
    ITE ((SyntaxKind (Vector ((Bit wordSz), memAddrSz))), (BinBitBool
    (memAddrSz, memAddrSz, (Lt memAddrSz), addr, (Const ((Bit memAddrSz),
    (ConstBit (memAddrSz, (natToWord memAddrSz pivot))))))),
    (mem_write_tree_aux d' base addr val0 memv),
    (mem_write_tree_aux d' pivot addr val0 memv)))
    depth

(** val write_mem : 'a1 expr -> 'a1 expr -> 'a1 expr -> 'a1 expr **)

let write_mem addr val0 memv =
  mem_write_tree_aux memAddrSz 0 addr val0 memv

