(** val default_csrs : cSRState **)

let default_csrs =
  { csr_cert_addr = 0; csr_status = 0; csr_err = 0; csr_heap_base = 0 }

(** val filtermap : ('a1 -> 'a2 option) -> 'a1 list -> 'a2 list **)

let rec filtermap f = function
| [] -> []
| x :: xs ->
  (match f x with
   | Some b -> b :: (filtermap f xs)
   | None -> filtermap f xs)

(** val snap_pt_to_graph : int -> (int -> int) -> partitionGraph **)

let snap_pt_to_graph next_id sizes =
  let modules0 =
    filtermap (fun i ->
      if (=) (sizes i) 0
      then None
      else Some (i, { module_region = (seq 0 (sizes i)); module_axioms = [] }))
      (rev (seq 0 next_id))
  in
  { pg_next_id = next_id; pg_modules = modules0 }

(** val abs_phase1 : kamiSnapshot -> vMState **)

let abs_phase1 s =
  { vm_graph = (snap_pt_to_graph s.snap_pt_next_id s.snap_pt_sizes);
    vm_csrs = default_csrs; vm_regs = (snapshot_regs_to_list s.snap_regs);
    vm_mem = (snapshot_mem_to_list s.snap_mem); vm_pc = s.snap_pc; vm_mu =
    s.snap_mu; vm_mu_tensor = (snapshot_tensor_to_list s.snap_mu_tensor);
    vm_err = s.snap_err }

